// Component shared functionality
void FlightTransitionComponent::Reset()
{
	m_smoothedTransitionAltitude.ResetZero();
	m_targetTransitionAltitude = 0.0f;
	m_onTransitionCompleteAbilityId = 0u;
}

void FlightTransitionComponent::Serialize(FArchive& archive)
{
	m_smoothedTransitionAltitude.Serialize(archive);
	archive << m_targetTransitionAltitude;
	archive << m_onTransitionCompleteAbilityId;
}

void FlightTransitionComponent::DrawComponentDebug() const
{
#if !UE_BUILD_SHIPPING
	if (!ImGui::CollapsingHeader("FlightTransitionComponent"))
	{
		return;
	}

	if (ImGui::BeginTable("ComponentValues", 2, ImGuiTableFlags_NoSavedSettings | ImGuiTableFlags_BordersInner))
	{
		ImGui::TableNextColumn();
		ImGui::Text("m_smoothedTransitionAltitude");
		ImGui::TableNextColumn();
		ImGui::Text("%.2f", m_smoothedTransitionAltitude.GetValue());
		ImGui::TableNextColumn();
		ImGui::Text("m_targetTransitionAltitude");
		ImGui::TableNextColumn();
		ImGui::Text("%.2f", m_targetTransitionAltitude);
		ImGui::TableNextColumn();
		ImGui::Text("m_onTransitionCompleteAbilityId");
		ImGui::TableNextColumn();
		ImGui::Text("%d", m_onTransitionCompleteAbilityId);
		ImGui::EndTable();
	}
#endif //!UE_BUILD_SHIPPING
}
